import subprocess
import json

command = args.get("command", "suggest")
prompt = args.get("prompt", "")

copilot_path = "~/.local/share/gh/copilot/copilot"

# Build the command based on type
if command == "suggest":
    cmd = f"{copilot_path} suggest -p '{prompt}'"
elif command == "explain":
    cmd = f"{copilot_path} explain -p '{prompt}'"
else:
    cmd = f"{copilot_path} -p '{prompt}'"

try:
    result = subprocess.run(
        cmd,
        shell=True,
        capture_output=True,
        text=True,
        timeout=60
    )

    return json.dumps({
        "success": result.returncode == 0,
        "stdout": result.stdout,
        "stderr": result.stderr,
        "returncode": result.returncode
    })
except subprocess.TimeoutExpired:
    return json.dumps({"success": False, "error": "Command timed out after 60 seconds"})
except Exception as e:
    return json.dumps({"success": False, "error": str(e)})
